const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const scenario = msg.evalScenario;
if (!scenario || typeof scenario !== 'object') {
  node.error('Missing msg.evalScenario', msg);
  return null;
}
const variantLabel = msg.evalVariantLabel || msg.payload?.variantLabel || 'skill-rubric-v1';
const correlationId = msg.correlationId || msg.evalGroupCorrelationId || msg.payload?.correlationId;
if (!uuidRe.test(String(correlationId || ''))) {
  node.error('Missing valid correlationId for eval group', msg);
  return null;
}
const evidence = scenario.evidence || {};
const expected = scenario.expected || {};
const basePrompt = scenario.prompt || [
  'Run this eval scenario.',
  '',
  'Return ONLY one valid JSON object. Do not use Markdown, headings, prose, tables, or code fences.',
  'Use only the supplied evidence. Do not browse. Do not invent facts. Mark unknowns explicitly.',
  '',
  'Scenario: ' + (scenario.title || scenario.id || 'unknown'),
  'Variant: ' + variantLabel,
  '',
  'Evidence JSON:',
  JSON.stringify(evidence, null, 2)
].join('\n');
const taskContexts = [
  { slug: 'eval-evidence', binding: 'context_inline', content: JSON.stringify(evidence, null, 2) },
  { slug: 'eval-expectations', binding: 'context_inline', content: JSON.stringify(expected, null, 2) }
];
if (variantLabel !== 'baseline-no-skill' && msg.evalSkillContext?.content) {
  taskContexts.unshift({
    slug: msg.evalSkillContext.slug || 'eval-skill-context',
    binding: msg.evalSkillContext.binding || 'skill',
    content: msg.evalSkillContext.content
  });
}
msg.correlationId = correlationId;
msg.evalGroupCorrelationId = correlationId;
msg.evalScenario = scenario;
msg.evalVariantLabel = variantLabel;
msg.payload = {
  taskType: 'run_eval',
  title: 'Eval: ' + (scenario.id || 'scenario') + ' / ' + variantLabel,
  tags: ['eval', scenario.id || 'scenario', variantLabel],
  correlationId,
  input: {
    scenario: { prompt: basePrompt },
    variantLabel,
    execution: { mode: 'vitro', workspace: 'none' },
    context: taskContexts
  }
};
return msg;

msg.evalTaskId = msg.payload?.taskId || msg.payload?.task?.id || msg.payload?.id || msg.taskId || null;
msg.evalAcceptedAttemptN = msg.payload?.acceptedAttemptN || msg.payload?.task?.acceptedAttemptN || 1;
return msg;

function extractJsonObject(text) {
  if (!text || typeof text !== 'string') return null;
  const fenced = text.match(/```json\s*([\s\S]*?)```/i) || text.match(/```\s*([\s\S]*?)```/);
  const candidates = [];
  if (fenced) candidates.push(fenced[1]);
  const first = text.indexOf('{');
  const last = text.lastIndexOf('}');
  if (first >= 0 && last > first) candidates.push(text.slice(first, last + 1));
  for (const candidate of candidates) {
    try { return JSON.parse(candidate); } catch (_) {}
  }
  return null;
}
const output = msg.payload || {};
const response = output.response || msg.result?.summary || '';
const analysis = extractJsonObject(response);
const expected = msg.evalScenario?.expected || {};
const requiredFields = msg.evalRequiredFields || ['decision', 'readinessScore0to100', 'decisionRationale', 'topActions', 'unknowns'];
const missingFields = analysis ? requiredFields.filter((field) => analysis[field] === undefined) : requiredFields;
const responseLower = response.toLowerCase();
const requiredFindings = expected.requiredFindings || [];
const missingFindings = requiredFindings.filter((item) => !responseLower.includes(String(item).toLowerCase()));
const forbiddenHits = (expected.forbidden || []).filter((item) => responseLower.includes(String(item).toLowerCase()));
const decision = analysis?.decision || null;
const decisionOk = decision ? (expected.acceptableDecisions || []).includes(decision) : false;
const checks = {
  parsedAnalysis: Boolean(analysis),
  requiredFields: missingFields.length === 0,
  decisionOk,
  noForbiddenHits: forbiddenHits.length === 0,
  requiredFindingsPresent: missingFindings.length === 0
};
const score0to100 = Math.round((Object.values(checks).filter(Boolean).length / Object.keys(checks).length) * 100);
msg.evalProducerScore = {
  scenarioId: msg.evalScenario?.id,
  variantLabel: msg.evalVariantLabel,
  correlationId: msg.correlationId,
  taskId: msg.evalTaskId || null,
  score0to100,
  checks,
  decision,
  missingFields,
  missingFindings,
  forbiddenHits,
  analysis,
  responseRef: msg.result?.outputRef || null
};
return msg;

const targetTaskId = msg.evalTaskId || msg.payload?.taskId;
const targetAttemptN = msg.evalAcceptedAttemptN || msg.payload?.acceptedAttemptN || 1;
if (!targetTaskId) {
  node.error('Missing target run_eval task id for judge_eval_attempt', msg);
  return null;
}
const criteria = msg.evalJudgeCriteria || [];
if (!Array.isArray(criteria) || criteria.length === 0) {
  node.error('Missing msg.evalJudgeCriteria', msg);
  return null;
}
msg.evalJudgeTargetTaskId = targetTaskId;
msg.evalJudgeTargetAttemptN = targetAttemptN;
msg.payload = {
  taskType: 'judge_eval_attempt',
  title: 'Judge eval: ' + (msg.evalScenario?.id || 'unknown') + ' / ' + (msg.evalVariantLabel || 'unknown'),
  tags: ['eval-judge', msg.evalScenario?.id || 'unknown', msg.evalVariantLabel || 'unknown'],
  correlationId: msg.correlationId,
  input: {
    targetTaskId,
    targetAttemptN,
    successCriteria: {
      version: 1,
      rubric: {
        rubricId: msg.evalJudgeRubricId || 'ab-eval-rubric',
        version: msg.evalJudgeRubricVersion || '1',
        contentHash: msg.evalJudgeRubricHash || 'node-red-rubric',
        criteria
      }
    }
  }
};
return msg;

const judgment = msg.payload || {};
const correlationId = msg.correlationId || msg.evalGroupCorrelationId || null;
const scenarioId = msg.evalScenario?.id || 'unknown';
const variantLabel = msg.evalVariantLabel || judgment.variantLabel || 'unknown';
const producerScore = msg.evalProducerScore?.score0to100 ?? null;
const judgeComposite = typeof judgment.composite === 'number' ? judgment.composite : null;
const judgeScore0to100 = judgeComposite === null ? null : Math.round(judgeComposite * 100);
const groups = flow.get('abEvalResults') || {};
const group = groups[correlationId] || { correlationId, scenarios: {}, createdAt: new Date().toISOString() };
const scenario = group.scenarios[scenarioId] || {};
scenario[variantLabel] = {
  correlationId,
  scenarioId,
  variantLabel,
  runEvalTaskId: msg.evalJudgeTargetTaskId || msg.evalTaskId || null,
  runEvalAttemptN: msg.evalJudgeTargetAttemptN || msg.evalAcceptedAttemptN || null,
  judgeTaskId: msg.evalJudgeTaskId || null,
  producerScore0to100: producerScore,
  judgeScore0to100,
  judgeComposite,
  verdict: judgment.verdict || null,
  scores: judgment.scores || [],
  updatedAt: new Date().toISOString()
};
group.scenarios[scenarioId] = scenario;
group.updatedAt = new Date().toISOString();
groups[correlationId] = group;
flow.set('abEvalResults', groups);
const variants = Object.values(scenario);
const ranked = variants.filter((item) => typeof item.judgeScore0to100 === 'number').sort((a, b) => b.judgeScore0to100 - a.judgeScore0to100);
const winner = ranked[0] || null;
const baseline = scenario['baseline-no-skill'];
const skill = scenario['skill-rubric-v1'];
const delta = baseline && skill ? {
  correlationId,
  scenarioId,
  baselineScore0to100: baseline.judgeScore0to100,
  skillScore0to100: skill.judgeScore0to100,
  judgeDelta0to100: baseline.judgeScore0to100 === null || skill.judgeScore0to100 === null ? null : skill.judgeScore0to100 - baseline.judgeScore0to100,
  baselineProducerScore0to100: baseline.producerScore0to100,
  skillProducerScore0to100: skill.producerScore0to100,
  producerDelta0to100: baseline.producerScore0to100 === null || skill.producerScore0to100 === null ? null : skill.producerScore0to100 - baseline.producerScore0to100
} : null;
msg.payload = {
  correlationId,
  scenarioId,
  variantLabel,
  producerScore0to100: producerScore,
  judgeScore0to100,
  verdict: judgment.verdict || null,
  scores: judgment.scores || [],
  winner,
  delta,
  variants: scenario
};
return msg;

function uuid() {
  return '10000000-1000-4000-8000-100000000000'.replace(/[018]/g, (c) =>
    (Number(c) ^ Math.floor(Math.random() * 16) >> Number(c) / 4).toString(16)
  );
}
msg.correlationId = uuid();
msg.evalVariantLabel = 'skill-rubric-v1';
msg.evalSkillContext = {
  slug: 'example-skill-context',
  binding: 'skill',
  content: 'Prefer concise structured analysis. Ground every recommendation in supplied evidence.'
};
msg.evalScenario = {
  id: 'demo-readiness',
  title: 'Demo traffic-fit readiness scenario',
  evidence: {
    offer: 'Trial subscription for a niche productivity tool',
    landingPage: 'Mentions benefits but lacks pricing and proof',
    tracking: ['page_view'],
    constraints: ['No browsing', 'Use evidence only']
  },
  expected: {
    acceptableDecisions: ['needs_work', 'not_ready'],
    requiredFindings: ['pricing', 'proof', 'tracking'],
    forbidden: ['ready to scale']
  }
};
msg.evalJudgeCriteria = [
  { id: 'json-validity', title: 'Valid structured output', weight: 0.2, description: 'Response is parseable and includes the required fields.' },
  { id: 'evidence-grounding', title: 'Evidence grounding', weight: 0.4, description: 'Findings use only supplied evidence and mark unknowns.' },
  { id: 'decision-quality', title: 'Decision quality', weight: 0.4, description: 'Decision and actions match the scenario expectations.' }
];
return msg;
